mapper.select:
SELECT o.id, o.user_id, o.product_id, o.seckill_activity_id, o.seckill_price, o.quantity, o.total_amount, o.status, o.address_id, o.receiver_name, o.receiver_phone, o.delivery_province, o.delivery_city, o.delivery_district, o.delivery_address, o.coupon_id, o.discount, o.user_coupon_id, o.created_at, o.updated_at, u.username, p.name AS product_name, p.image_url AS product_image_url FROM `order` o JOIN user u ON o.user_id = u.id JOIN product p ON o.product_id = p.id
AND o.user_id = #{userId}
ORDER BY o.created_at DESC LIMIT #{size} OFFSET #{offset}
